var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이, 이건 엘릭서?","JPN":"こ、これはエリクサー？","ENG":"I-isn't that the Elixir?","TWN":"這，這是聖水？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"이 약물에 대해 아는 눈치네요?","JPN":"この薬物について知っているようですね。","ENG":"You seem to recognize it.","TWN":"你似乎知道這種藥物？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"소문으로만 들었네.","JPN":"噂で聞いたことがある。","ENG":"I've only heard rumors.","TWN":"只是聽說過。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"일반인에게 카운터와 비견되는 힘을 가져다주는 약물로 알고 있지.","JPN":"一般人にもカウンターに匹敵する力を与えてくれる薬物だと聞いた。","ENG":"The Elixir said to grant ordinary people power comparable to Counters.","TWN":"我知道這是一種能讓普通人擁有媲美制裁者力量的藥物。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하지만…… 심각한 부작용을 초래한다고 하더군.","JPN":"しかし……深刻な副作用が伴うらしい。","ENG":"But... it supposedly comes with severe side effects.","TWN":"但是……聽說有嚴重的副作用。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"제조법 또한 관리국에서 엄중히 관리하고 있다네.","JPN":"製造法も管理局で厳重に管理されている。","ENG":"Not to mention, the formula is strictly controlled by the Administration.","TWN":"製造方法在管理局手裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네가 누구인지는 모르겠지만, 엘릭서 자체가 불법이란 소리일세.","JPN":"君が誰かは知らないが、エリクサー自体、違法薬物だということだ。","ENG":"I don't know who you are, but the Elixir itself is illegal.","TWN":"不知道你是誰，但我可以告訴你，聖水本身就是非法的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"하하. 그건 걱정할 필요 없습니다.","JPN":"はは。それはご心配なく。","ENG":"Haha. That's not something you need to worry about.","TWN":"哈哈，不用擔心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"제가 직접 제조한 것들이거든요.","JPN":"僕が自分で作ったものなので。","ENG":"After all, I made these myself.","TWN":"這些都是我親手製作的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"직접 만들었다고 해서 합법이 되지는 않네.","JPN":"自分で作ったからと言って合法にはならない。","ENG":"Just because you made it doesn't make it legal.","TWN":"自己做的也不代表合法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신이 <color=#ffd34c>겪은 일</color>에 대해선 유감입니다. 루드윅 폰 에르헨 박사님.","JPN":"あなたが<color=#ffd34c>経験したこと</color>については、非常に残念だと思っています。ルードヴィヒ・フォン・ヘルヒェン博士。","ENG":"I must say, I sympathize with <color=#ffd34c>what you've been through</color>, Dr. Ludwig von Herrchen.","TWN":"對於你<color=#ffd34c>經歷的事情</color>，我深感遺憾，路易博士。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신의 침식학 논문들을 꽤 흥미롭게 봤어요.","JPN":"あなたが書いた侵食学の論文は非常に興味深いものでした。","ENG":"I've found your research on Corruption quite fascinating.","TWN":"我對你的侵蝕學論文非常感興趣。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"그건 제 흥미를 충족해 준 답례라고 생각하고 받아주면 좋겠군요.","JPN":"僕の好奇心を満たしてくれたお礼だと思って、受け取って欲しいのです。","ENG":"Consider this my way of returning the favor.","TWN":"那就當作是你滿足我的興趣的謝禮吧，希望你能接受。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나에게 왜 이러는 거지?","JPN":"なぜ私にこんなことをする？","ENG":"Why are you doing this?","TWN":"為什麼要送我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"말씀드렸잖아요. 당신의 논문을 흥미롭게 봤고, 그에 대한 답례라고.","JPN":"言ったじゃないですか。あなたの論文を興味深く読ませていただいたことへのお礼だと。","ENG":"I already told you. I was impressed by your research, and this is my way of showing appreciation.","TWN":"我不是說過了嗎？我對你的論文很感興趣，這是對你的答謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"특히나, 박사님이 마지막으로 썼던 논문이 인상 깊었어요.","JPN":"特に、博士が最後に書いた論文が印象的でした。","ENG":"Your last paper, in particular, left quite an impression.","TWN":"尤其是博士最後寫的那篇論文，給我留下了深刻的印象。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ffd34c>이상 침식 현상으로 인한 유전자 변화와 내재한 인자의 가능성</color>.","JPN":"<color=#ffd34c>異常侵食現象による遺伝子の変化および内在ファクターの可能性について</color>。","ENG":"<color=#ffd34c>Genetic Alterations from the Aberrant Counterside Effect and the Potential of Latent Factors</color>.","TWN":"<color=#ffd34c>由異常侵蝕現象引起基因變化和產生內在因子的可能性</color>。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"완성되지 못한 채 세상 밖으로 나온 실패작이지.","JPN":"未完成のまま世に出てしまった失敗作だ。","ENG":"A failure that was released into the world incomplete.","TWN":"尚未完成就被帶到世上的失敗作。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"엘릭서는 못 본 척해줄 테니…….","JPN":"エリクサーのことは見逃してやるから……","ENG":"I'll pretend you never showed me the Elixir, so–","TWN":"我會假裝沒看到聖水……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"제가 마침 침식학과 유전공학에도 관심이 있었거든요.","JPN":"僕、ちょうど侵食学と遺伝子工学にも興味があるんです。","ENG":"As it happens, I have a keen interest in both Corruption and genetic engineering.","TWN":"我正好對侵蝕學和遺傳學也感興趣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L37_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"박사님의 연구에 대해 더 자세히 알 수 있을까요?","JPN":"あなたの研究について、詳しく聞かせてくれませんか？","ENG":"Would you be willing to share more details about your research?","TWN":"能詳細了解一下博士的研究嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"……거절하겠네.","JPN":"……断る。","ENG":"...I decline.","TWN":"……我拒絕。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나는 이미 학계에서 은퇴하고, 죽을 날만 기다리는 사람이야.","JPN":"私はもう学会を引退し、死を待つだけの人間だ。","ENG":"I've already retired from academia. I'm just waiting for my time to run out.","TWN":"我已經從學界退休，現在只是在等待死亡的那一天。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"아쉽군요.","JPN":"残念ですね。","ENG":"What a shame.","TWN":"好可惜喔……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신이라면 저 실패를 딛고 나아가, 새로운 지평을 열 수 있을 텐데.","JPN":"あなたならあの失敗を乗り越え、新境地を開けるはずなのに。","ENG":"You, of all people, could rise above failure and open new doors for humanity.","TWN":"如果是你的話，一定能克服失敗，開創新的局面。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"칭찬은 고맙지만, 난 이미 늦었네.","JPN":"賞賛はありがたいが、もう私は手遅れだ。","ENG":"Flattering, but I'm far too late for that.","TWN":"謝謝誇獎，但我已經遲到了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"보내드린 엘릭서는 박사님의 침식을 늦춰주는 역할을 할 겁니다.","JPN":"お送りしたエリクサーは、あなたの侵食を遅らせてくれるでしょう。","ENG":"The Elixir I sent you will slow down your Corruption.","TWN":"送去的聖水會延緩博士的侵蝕。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"주기적으로 엘릭서를 보내드리도록 하죠.","JPN":"今後定期的にエリクサーをお送りします。","ENG":"I'll make sure you receive it regularly.","TWN":"我會定期送聖水給你的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신을 후원하겠습니다. 루드윅 박사님.","JPN":"あなたを支援するということです、ルードヴィヒ博士。","ENG":"I will sponsor you, Dr. Ludwig.","TWN":"我會支援你的，路易博士。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이렇게까지 나를 이용하려는 이유가 뭔가?","JPN":"ここまでして私を利用する理由は何だ？","ENG":"Why go this far to use me?","TWN":"你到底為什麼要這樣利用我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"당신이 완성하지 못한 연구의 끝을 보고 싶지 않으신가요?","JPN":"完成できなかった研究を最後まで成し遂げたいとは思いませんか？","ENG":"Don't you want to see the end of the research you never got to complete?","TWN":"你不想看看你未完成的研究最後的結果嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"이대로 볼품없이 죽는 것보단, 당당하게 침식을 극복하는 편이 낫잖아요?","JPN":"このままみすぼらしく死を迎えるより、堂々と侵食を乗り越えるほうがマシなはずです。","ENG":"Wouldn't it be better to overcome the Corruption than to die a meaningless death?","TWN":"與其這樣毫無尊嚴地死去，不如堂堂正正地克服侵蝕，不是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"……그 말이 맞아.","JPN":"……その通りだ。","ENG":"...You're right.","TWN":"……你說的沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나는 살아서…… 연구를 완성하고 싶었네.","JPN":"私は生きて……研究を完成したかった。","ENG":"I wanted to live... and finish my research.","TWN":"我想活著……完成研究。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"좋아요. 좀 더 본연의 욕망에 충실해지셨군요.","JPN":"それです。少し本来の欲望に忠実になりましたね。","ENG":"Good. Now you're embracing your true desires.","TWN":"很好，你變得更加忠於自己的欲望了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"상으로, 저도 제 본연의 목적을 말씀드리죠.","JPN":"そのご褒美に僕も自分の真の目的をお話しします。","ENG":"As a reward, I'll share mine as well.","TWN":"既然如此，我也說說我的本來目的吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"저는 <color=#ffd34c>잡고 싶은 괴물이 있습니다.</color>","JPN":"<color=#ffd34c>捕まえたい怪物がいます。</color>","ENG":"There is <color=#ffd34c>a monster I wish to capture</color>.","TWN":"我有<color=#ffd34c>想抓到的怪物。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"그 괴물을 잡고 싶어서, 당신을 후원하려는 거예요.","JPN":"その怪物を捕まえるために、あなたを支援すると決めたのです。","ENG":"That's why I'm investing in you.","TWN":"因為我想抓住那個怪物，所以才會支持你。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"잡고 싶은 괴물……?","JPN":"捕まえたい怪物……？","ENG":"A monster...?","TWN":"想抓到的怪物……？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"네. 지금의 저는 쳐다볼 수도 없을 만큼 무서운 괴물이죠.","JPN":"はい。今の僕では到底目を合わせることすらできない程の恐ろしい怪物です。","ENG":"Yes. A beast so terrifying, I can't even face it as I am now.","TWN":"是的，現在的我連看都不敢看的可怕怪物呢。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"UNKNOWN_MOONLIGHT_NPC_NULL","text":{"KOREA":"어쩌면, 우리는 좋은 파트너가 될 수 있을 것 같군요.","JPN":"もしかしたら、僕たちはいいパートナーになれるかもしれませんね。","ENG":"Perhaps... we'll make excellent partners.","TWN":"或許，我們可以成為好夥伴。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신, 제정신이야?","JPN":"あなた、正気なの？","ENG":"Are you out of your mind?!","TWN":"你瘋了嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"서로 손해 볼 것이 없는 거래였네.","JPN":"お互い損をしない取引だった。","ENG":"It was a mutually beneficial arrangement.","TWN":"這是一筆互利的交易。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네가 이제껏 한 짓과 같지.","JPN":"君が今までしてきたことと変わらないさ。","ENG":"Not so different from what you've been doing.","TWN":"就和你以前做的一樣。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 무슨……!","JPN":"それはどういう……！","ENG":"Don't be ridiculous...!","TWN":"什麼……!"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"돈을 벌기 위해 아무렇지 않게 사기를 치지 않았나?","JPN":"儲けるために、平気で詐欺をしてきたではないか？","ENG":"Haven't you been conning people to make money?","TWN":"為了賺錢，你不是也經常騙人嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나도 마찬가지네.","JPN":"私も同じだ。","ENG":"I did the same.","TWN":"我也一樣。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"침식을 극복할 수 있다면 뭐든지 할 수 있어.","JPN":"侵食を乗り越えるためなら、どんなことだってする。","ENG":"If it meant overcoming the Corruption, I would do anything.","TWN":"只要能克服侵蝕，什麼都能做到。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};